import{_ as d,C as h,o as t,c as p,a2 as r,b as l,w as a,a as i,E as s,a3 as n,j as c}from"./chunks/framework.Bj6f68Cg.js";const S=JSON.parse('{"title":"SliceRAG","description":"","frontmatter":{},"headers":[],"relativePath":"projects/slicerag.md","filePath":"projects/slicerag.md"}'),u={name:"projects/slicerag.md"};function g(m,e,y,A,b,k){const o=h("Mermaid");return t(),p("div",null,[e[2]||(e[2]=r('<h1 id="slicerag" tabindex="-1">SliceRAG <a class="header-anchor" href="#slicerag" aria-label="Permalink to &quot;SliceRAG&quot;">​</a></h1><p>Gateway가 확정한 <code>project_id</code> 범위 안에서만 문서를 저장·검색하는 Tenant-isolated RAG Data Plane MVP입니다.</p><h2 id="📌-status-repository" tabindex="-1">📌 Status &amp; Repository <a class="header-anchor" href="#📌-status-repository" aria-label="Permalink to &quot;📌 Status &amp; Repository&quot;">​</a></h2><ul><li><strong>상태</strong>: <code>MVP</code></li><li><strong>저장소 주소</strong>: <a href="https://github.com/devcy0922/slicerag" target="_blank" rel="noreferrer">GitHub (devcy0922/slicerag)</a></li><li><strong>라이선스</strong>: Apache 2.0</li><li><strong>주요 언어</strong>: Python</li></ul><hr><h2 id="_1-problem" tabindex="-1">1. Problem <a class="header-anchor" href="#_1-problem" aria-label="Permalink to &quot;1. Problem&quot;">​</a></h2><p>여러 프로젝트가 하나의 Vector Store를 공유하면 검색 품질보다 먼저 다른 프로젝트의 문서가 결과에 섞이지 않는 Scope Invariant를 보장해야 합니다. 외부 인증과 내부 검색 책임이 섞이면 RAG 서비스가 사용자 권한까지 중복 구현하게 되고 보안 경계도 불분명해집니다.</p><h2 id="_2-why-i-built-it" tabindex="-1">2. Why I Built It <a class="header-anchor" href="#_2-why-i-built-it" aria-label="Permalink to &quot;2. Why I Built It&quot;">​</a></h2><p>외부 인증과 정책은 Gateway가 담당하고 SliceRAG는 내부 Token과 <code>project_id</code>를 검증한 뒤 동일 Namespace 안에서만 Ingest, Search, Document 조회를 수행하도록 책임을 분리했습니다.</p><h2 id="_3-scope" tabindex="-1">3. Scope <a class="header-anchor" href="#_3-scope" aria-label="Permalink to &quot;3. Scope&quot;">​</a></h2><ul><li>Gateway 전용 <code>/internal/*</code> API와 Shared Internal Token 검증</li><li><code>project_id</code>별 Document, Chunk, Search Namespace</li><li>PostgreSQL + pgvector 또는 In-Memory Store 전환</li><li>Hash Embedding과 Gateway 경유 OpenAI-compatible Embedding</li><li>Chunk와 Source 근거를 함께 반환하는 Search Contract</li><li>교차 프로젝트 조회와 예약 식별자 차단 테스트</li></ul><hr><h2 id="_4-architecture" tabindex="-1">4. Architecture <a class="header-anchor" href="#_4-architecture" aria-label="Permalink to &quot;4. Architecture&quot;">​</a></h2>',13)),(t(),l(n,null,{default:a(()=>[s(o,{id:"mermaid-83",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20Client%5B%22IDE%20%2F%20SaaS%20Client%22%5D%20--%3E%20Gateway%5B%22Auth%20%26%20Policy%20Gateway%22%5D%0A%20%20%20%20Gateway%20--%3E%7C%22project_id%20%2B%20internal%20token%22%7C%20RAG%5B%22SliceRAG%20Internal%20API%22%5D%0A%20%20%20%20RAG%20--%3E%20Scope%5B%22Scope%20Validation%22%5D%0A%20%20%20%20Scope%20--%3E%20Store%5B%22PostgreSQL%20%2B%20pgvector%22%5D%0A%20%20%20%20Scope%20-.%20%22Test%20%2F%20Demo%22%20.-%3E%20Memory%5B%22In-Memory%20Store%22%5D%0A%20%20%20%20Gateway%20--%3E%20Embed%5B%22OpenAI-compatible%20Embedding%20Gateway%22%5D%0A%20%20%20%20RAG%20--%3E%20Embed%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[i(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=c("h2",{id:"_5-data-flow",tabindex:"-1"},[i("5. Data Flow "),c("a",{class:"header-anchor",href:"#_5-data-flow","aria-label":'Permalink to "5. Data Flow"'},"​")],-1)),(t(),l(n,null,{default:a(()=>[s(o,{id:"mermaid-87",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20Gateway%0A%20%20%20%20participant%20RAG%20as%20SliceRAG%0A%20%20%20%20participant%20Store%20as%20pgvector%0A%20%20%20%20Gateway-%3E%3ERAG%3A%20search(project_id%2C%20query)%20%2B%20internal%20token%0A%20%20%20%20RAG-%3E%3ERAG%3A%20token%EA%B3%BC%20project_id%20%ED%98%95%EC%8B%9D%20%EA%B2%80%EC%A6%9D%0A%20%20%20%20RAG-%3E%3EStore%3A%20WHERE%20project_id%20%3D%20requested%20project%0A%20%20%20%20Store--%3E%3ERAG%3A%20scoped%20chunks%20%2B%20sources%0A%20%20%20%20RAG--%3E%3EGateway%3A%20memory_hit%20%2B%20evidence%0A%20%20%20%20Gateway-%3E%3EGateway%3A%20%EC%9D%91%EB%8B%B5%20%EC%A0%95%EC%B1%85%EA%B3%BC%20Audit%20%EC%A0%81%EC%9A%A9%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[i(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=r(`<h2 id="_6-key-design-decisions" tabindex="-1">6. Key Design Decisions <a class="header-anchor" href="#_6-key-design-decisions" aria-label="Permalink to &quot;6. Key Design Decisions&quot;">​</a></h2><ul><li><strong>Gateway가 Identity를 확정</strong>: SliceRAG는 외부 API Key나 사용자 목록을 다루지 않고 Gateway가 전달한 Project Scope만 검증합니다.</li><li><strong>저장소 계층에서도 Scope 강제</strong>: In-Memory와 PostgreSQL 구현 모두 Search와 Document 조회에 <code>project_id</code> 조건을 적용합니다.</li><li><strong>열거 API 비노출</strong>: Project 목록이나 Cross-project 검색 Endpoint를 제공하지 않고 <code>all</code> 같은 예약 식별자를 API와 Migration에서 거부합니다.</li></ul><h2 id="_7-security-considerations" tabindex="-1">7. Security Considerations <a class="header-anchor" href="#_7-security-considerations" aria-label="Permalink to &quot;7. Security Considerations&quot;">​</a></h2><ul><li>내부 API는 <code>X-SliceRAG-Internal-Token</code> 없이는 실행되지 않습니다.</li><li>다른 Project의 Document ID를 직접 입력해도 <code>project_id</code>가 일치하지 않으면 조회되지 않습니다.</li><li>Embedding Provider는 SliceRAG가 직접 외부로 호출하지 않고 Gateway 정책 경계를 경유하도록 구성할 수 있습니다.</li></ul><h2 id="_8-observability" tabindex="-1">8. Observability <a class="header-anchor" href="#_8-observability" aria-label="Permalink to &quot;8. Observability&quot;">​</a></h2><ul><li><code>/health</code>를 통해 Liveness를 확인합니다.</li><li>Search 결과에 <code>project_id</code>, <code>memory_hit</code>, Chunk와 Source ID를 반환해 상위 Gateway가 Audit Metadata를 남길 수 있습니다.</li><li>현재 독립 Prometheus Dashboard는 제공하지 않으며 Gateway Audit과 서비스 로그를 주요 추적 경로로 사용합니다.</li></ul><h2 id="_9-technology-stack" tabindex="-1">9. Technology Stack <a class="header-anchor" href="#_9-technology-stack" aria-label="Permalink to &quot;9. Technology Stack&quot;">​</a></h2><ul><li><strong>API</strong>: Python, FastAPI, Pydantic</li><li><strong>Store</strong>: PostgreSQL, pgvector, In-Memory</li><li><strong>Quality Gate</strong>: Ruff, Mypy, Pytest</li><li><strong>Packaging</strong>: Docker Compose</li></ul><h2 id="_10-running-locally" tabindex="-1">10. Running Locally <a class="header-anchor" href="#_10-running-locally" aria-label="Permalink to &quot;10. Running Locally&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span></span></code></pre></div><p>Compose는 내부 서비스를 Loopback에 바인딩하며 외부 Client는 SliceRAG가 아니라 Gateway에 연결해야 합니다.</p><h2 id="_11-current-limitations" tabindex="-1">11. Current Limitations <a class="header-anchor" href="#_11-current-limitations" aria-label="Permalink to &quot;11. Current Limitations&quot;">​</a></h2><ul><li>외부 사용자 인증, 권한 관리와 Billing은 범위에 포함하지 않습니다.</li><li>현재 Chunking은 공개 API Contract와 격리 검증에 필요한 범위이며 PDF Layout 분석이나 Temporal Pipeline을 구현했다고 주장하지 않습니다.</li><li>운영 규모의 Backpressure와 Queue Orchestration은 아직 제공하지 않습니다.</li></ul><h2 id="_12-next-steps" tabindex="-1">12. Next Steps <a class="header-anchor" href="#_12-next-steps" aria-label="Permalink to &quot;12. Next Steps&quot;">​</a></h2><ul><li>Tenant별 Ingest/Search Metric과 Storage Quota 추가</li><li>PostgreSQL Row Level Security 적용 가능성 검증</li><li>대규모 Ingestion Queue와 Deduplication 설계</li></ul>`,15))])}const P=d(u,[["render",g]]);export{S as __pageData,P as default};
